  // ── Salon dashboard body ────────────────────────────────────────────────────
  "salon.autoConfirm.title":             { ru: "Автоматическое подтверждение заявок", ua: "Автоматичне підтвердження заявок", en: "Automatic booking confirmation", pl: "Automatyczne potwierdzanie rezerwacji" },
  "salon.autoConfirm.body":              { ru: "Если включено — заявки из выбранного канала сразу становятся подтверждёнными без шага одобрения мастером. Мастер всё равно получает уведомление о записи.", ua: "Якщо увімкнено — заявки з вибраного каналу одразу стають підтвердженими без кроку затвердження майстром. Майстер усе одно отримує сповіщення про запис.", en: "When enabled, bookings from the selected channel are instantly confirmed without manual approval. The master still receives a notification.", pl: "Gdy włączone, rezerwacje z wybranego kanału są od razu potwierdzane bez ręcznego zatwierdzenia. Mistrz nadal otrzymuje powiadomienie." },
  "salon.channels.web.label":            { ru: "Веб-чат (manicbot.com / TikTok / соцсети)", ua: "Веб-чат (manicbot.com / TikTok / соцмережі)", en: "Web chat (manicbot.com / TikTok / social)", pl: "Chat web (manicbot.com / TikTok / social)" },
  "salon.channels.web.hint":             { ru: "Записи через виджет на странице салона. Рекомендуется ВКЛ — клиенты ждут мгновенного ответа.", ua: "Записи через віджет на сторінці салону. Рекомендується УВІМК — клієнти чекають миттєвої відповіді.", en: "Bookings via the widget on your salon page. Recommended ON — clients expect instant responses.", pl: "Rezerwacje przez widget na stronie salonu. Zalecane WŁ — klienci oczekują natychmiastowej odpowiedzi." },
  "salon.channels.telegram.hint":        { ru: "Записи через Telegram-бота. По умолчанию ВЫКЛ — мастер видит заявку и подтверждает вручную.", ua: "Записи через Telegram-бота. За замовчуванням ВИМК — майстер бачить заявку і підтверджує вручну.", en: "Bookings via the Telegram bot. Off by default — the master sees the request and confirms manually.", pl: "Rezerwacje przez bota Telegram. Domyślnie WYŁ — mistrz widzi prośbę i potwierdza ręcznie." },
  "salon.channels.whatsapp.hint":        { ru: "Записи через WhatsApp Business. По умолчанию ВЫКЛ.", ua: "Записи через WhatsApp Business. За замовчуванням ВИМК.", en: "Bookings via WhatsApp Business. Off by default.", pl: "Rezerwacje przez WhatsApp Business. Domyślnie WYŁ." },
  "salon.channels.instagram.label":      { ru: "Instagram Direct", ua: "Instagram Direct", en: "Instagram Direct", pl: "Instagram Direct" },
  "salon.channels.instagram.hint":       { ru: "Записи через Instagram DM. По умолчанию ВЫКЛ.", ua: "Записи через Instagram DM. За замовчуванням ВИМК.", en: "Bookings via Instagram DM. Off by default.", pl: "Rezerwacje przez Instagram DM. Domyślnie WYŁ." },

  // ── 0074 Auto-suggest favorite master ──────────────────────────────────────
  "salon.favoriteSuggest.title":         { ru: "Любимый мастер", ua: "Улюблений майстер", en: "Favorite master", pl: "Ulubiony mistrz" },
  "salon.favoriteSuggest.body":          { ru: "Если включено — при создании записи система автоматически предложит мастера, к которому клиент ходит чаще всего (или закреплённого вручную в карточке клиента). Работает по всем каналам, где клиент уже узнан.", ua: "Якщо увімкнено — при створенні запису система автоматично запропонує майстра, до якого клієнт ходить найчастіше (або закріпленого вручну в картці клієнта). Працює по всіх каналах, де клієнт уже впізнаний.", en: "When enabled, the system pre-picks the master a returning client visits most often (or the one you pinned manually on their card). Works across every channel where the client is already recognized.", pl: "Gdy włączone, system automatycznie wybiera mistrza, do którego klient chodzi najczęściej (lub przypiętego ręcznie w karcie klienta). Działa we wszystkich kanałach, gdzie klient jest już rozpoznany." },
  "salon.favoriteSuggest.web.hint":      { ru: "Подсказка работает в форме «Новая запись» и в виджете на сайте.", ua: "Підказка працює у формі «Новий запис» і у віджеті на сайті.", en: "Suggestion works in the New Booking form and on the website widget.", pl: "Podpowiedź działa w formularzu «Nowa rezerwacja» i na widgetcie strony." },
  "salon.favoriteSuggest.telegram.hint": { ru: "В Telegram-боте любимый мастер выделяется звёздочкой и поднимается в верх списка.", ua: "У Telegram-боті улюблений майстер виділяється зірочкою і піднімається у верх списку.", en: "In the Telegram bot, the favorite master is marked with a star and moved to the top of the list.", pl: "W bocie Telegram ulubiony mistrz jest oznaczony gwiazdką i przesuwany na górę listy." },

