  "channels.ig.test.failed":             { ru: "Meta отклонила отправку", ua: "Meta відхилила надсилання", en: "Meta rejected the send", pl: "Meta odrzuciła wysyłanie" },
  "channels.ig.test.outsideWindowHint":  { ru: "Подсказка: правила Meta запрещают отправлять DM получателю, который не писал боту в течение 24 часов. Попросите клиента написать боту, потом повторите тест.", ua: "Підказка: правила Meta забороняють надсилати DM отримувачу, який не писав боту протягом 24 годин. Попросіть клієнта написати боту, потім повторіть тест.", en: "Hint: Meta forbids DMs to recipients who haven't messaged the bot in the last 24h. Ask the client to DM the bot first, then retry the test.", pl: "Wskazówka: zasady Meta zabraniają wysyłania DM-ów do odbiorców, którzy nie pisali do bota w ciągu ostatnich 24h. Poproś klienta o napisanie do bota, a następnie ponów test." },
  "channels.ig.paused":                  { ru: "На паузе", ua: "На паузі", en: "Paused", pl: "Wstrzymane" },
  "channels.ig.pauseAction":             { ru: "Поставить на паузу", ua: "Поставити на паузу", en: "Pause", pl: "Wstrzymaj" },
  "channels.ig.pauseConfirm":            { ru: "Бот перестанет принимать и отправлять сообщения. Токен сохранится — можно возобновить в один клик.", ua: "Бот перестане приймати і надсилати повідомлення. Токен збережеться — можна відновити в один клік.", en: "The bot stops receiving and sending. The token is preserved — you can resume with one click.", pl: "Bot przestanie odbierać i wysyłać. Token zostanie zachowany — można wznowić jednym kliknięciem." },
  "channels.ig.resumeAction":            { ru: "Возобновить", ua: "Відновити", en: "Resume", pl: "Wznów" },
