  "channels.ig.removeConfirm":           { ru: "Удалить канал и токен? Для повторного подключения понадобится новый OAuth.", ua: "Видалити канал і токен? Для повторного підключення знадобиться новий OAuth.", en: "Delete the channel and token? Reconnecting will require a fresh OAuth.", pl: "Usunąć kanał i token? Ponowne podłączenie będzie wymagać nowego OAuth." },
  "channels.ig.reauth.button":           { ru: "Переподключить", ua: "Перепідключити", en: "Reconnect", pl: "Połącz ponownie" },
  "channels.ig.reauth.confirmTitle":     { ru: "Переподключить аккаунт?", ua: "Перепідключити акаунт?", en: "Reconnect the account?", pl: "Połączyć ponownie konto?" },
  "channels.ig.reauth.confirmBody":      { ru: "Текущий канал будет удалён, и мы откроем OAuth-окно для нового подключения. Существующие записи останутся.", ua: "Поточний канал буде видалено, і ми відкриємо OAuth-вікно для нового підключення. Існуючі записи залишаться.", en: "The current channel will be removed and we'll open a fresh OAuth window. Existing bookings stay intact.", pl: "Bieżący kanał zostanie usunięty, a my otworzymy nowe okno OAuth. Istniejące rezerwacje pozostaną." },
  "channels.ig.errorType.token_decrypt_failed": { ru: "Не удалось расшифровать токен Instagram — возможно, ключ шифрования был ротирован. Подключите аккаунт заново.", ua: "Не вдалося розшифрувати токен Instagram — можливо, ключ шифрування було ротовано. Підключіть акаунт заново.", en: "Couldn't decrypt the Instagram token — the encryption key may have been rotated. Reconnect the account.", pl: "Nie można odszyfrować tokenu Instagram — być może klucz szyfrowania został zmieniony. Połącz konto ponownie." },
  "channels.ig.errorType.token_rejected":       { ru: "Meta отклонила токен. Скорее всего истёк или был отозван — нужно переподключить аккаунт.", ua: "Meta відхилила токен. Найімовірніше, минув термін дії або токен було відкликано — потрібно перепідключити акаунт.", en: "Meta rejected the token. Most likely expired or revoked — reconnect the account.", pl: "Meta odrzuciła token. Najprawdopodobniej wygasł lub został odwołany — połącz konto ponownie." },
  "channels.ig.errorType.subscription_lost":    { ru: "Подписка на webhook потеряна — DM могут не доходить. Нажмите «Переподключить» либо обратитесь в поддержку.", ua: "Підписку на webhook втрачено — DM можуть не доходити. Натисніть «Перепідключити» або зверніться до підтримки.", en: "The webhook subscription was lost — DMs may not be delivered. Tap «Reconnect» or contact support.", pl: "Subskrypcja webhooka została utracona — DM-y mogą nie być dostarczane. Kliknij «Połącz ponownie» lub skontaktuj się z pomocą techniczną." },
  "channels.ig.errorType.health_probe_failed":  { ru: "Проверка здоровья канала не прошла из-за сетевой ошибки. Скоро попробуем снова.", ua: "Перевірка здоров'я каналу не пройшла через мережеву помилку. Скоро спробуємо знову.", en: "The channel-health probe failed due to a network error. We'll retry shortly.", pl: "Sprawdzanie stanu kanału nie powiodło się z powodu błędu sieci. Wkrótce ponowimy próbę." },
  "channels.ig.errorType.signature_mismatch":   { ru: "Webhook от Meta пришёл с неверной подписью. Возможно поменялся App Secret — проверьте настройки.", ua: "Webhook від Meta надійшов з невірним підписом. Можливо змінився App Secret — перевірте налаштування.", en: "A Meta webhook came in with an invalid signature. The App Secret may have changed — verify the configuration.", pl: "Webhook od Meta przyszedł z nieprawidłowym podpisem. Być może zmienił się App Secret — sprawdź konfigurację." },
  "channels.ig.errorType.resubscribe_failed":   { ru: "Не получилось повторно подписаться на webhook. Скорее всего токен ослаб — нажмите «Переподключить».", ua: "Не вдалося повторно підписатися на webhook. Найімовірніше, токен ослаб — натисніть «Перепідключити».", en: "Couldn't re-subscribe to the webhook. The token likely degraded — tap «Reconnect».", pl: "Nie udało się ponownie zasubskrybować webhooka. Najprawdopodobniej token osłabł — kliknij «Połącz ponownie»." },
  "channels.ig.errorType.needs_reauth":         { ru: "Бот не может отправить сообщение — Meta требует повторной авторизации. Нажмите «Переподключить».", ua: "Бот не може надіслати повідомлення — Meta вимагає повторної авторизації. Натисніть «Перепідключити».", en: "The bot can't send messages — Meta requires re-authorization. Tap «Reconnect».", pl: "Bot nie może wysyłać wiadomości — Meta wymaga ponownej autoryzacji. Kliknij «Połącz ponownie»." },
  "channels.ig.errorType.unknown":              { ru: "Ошибка интеграции с Instagram — детали смотрите в логах God Mode.", ua: "Помилка інтеграції з Instagram — деталі дивіться в логах God Mode.", en: "Instagram integration error — see God Mode logs for details.", pl: "Błąd integracji z Instagramem — szczegóły w logach God Mode." },
  "channels.metaContactSupport":         { ru: "После настройки вебхука в Meta Business Manager обратитесь в поддержку для активации канала.", ua: "Після налаштування вебхука в Meta Business Manager зверніться до підтримки для активації каналу.", en: "After setting up the webhook in Meta Business Manager, contact support to activate the channel.", pl: "Po skonfigurowaniu webhooka w Meta Business Manager skontaktuj się z pomocą techniczną, aby aktywować kanał." },
  "channels.webhookUnavailable":         { ru: "Webhook данные недоступны — проверьте настройки сервера", ua: "Дані webhook недоступні — перевірте налаштування сервера", en: "Webhook data unavailable — check server configuration", pl: "Dane webhooka niedostępne — sprawdź konfigurację serwera" },
