  "masterDetail.password.actionLabel.peek":  { ru: "Показать пароль мастера {name}",                                                                      ua: "Показати пароль майстра {name}",                                                                              en: "Show password for master {name}",                                                                      pl: "Pokaż hasło mistrza {name}" },
